// src/redux/form/formSlice.js
import { createSlice } from '@reduxjs/toolkit';

const initialState = {
  formData: {
    username: '',
    email: '',
    password: '',
    module: 'defaultModule', // Valor por defecto o ajusta según sea necesario
  },
};

const formSlice = createSlice({
  name: 'form',
  initialState,
  reducers: {
    saveFormData: (state, action) => {
      state.formData = {
        ...state.formData,
        ...action.payload,
      };
    },
    clearFormData: (state) => {
      state.formData = initialState.formData;
    },
  },
});

export const { saveFormData, clearFormData } = formSlice.actions;
export default formSlice.reducer;
